    const distz = Math.abs(z1 - z);

    if (disty >= distx && disty >= distz) {
      y += dy;
    } else if (distz >= distx && distz >= disty) {
      z += dz;
    } else {
      x += dx;
    }
    grid.set(x, y, z, color);
  }
}

